INSERT OR IGNORE INTO innovation_theory (id, name_ja, name_en, definition, impact_summary, subfield, category, school_of_thought, era_start, schumpeter_layer, innovation_type, cognitive_mechanism, key_researchers, key_works, keywords_ja, keywords_en) VALUES
('inno_pol_201','イノベーション産出指標の国際比較研究','International Comparative Research on Innovation Output Indicators','特許出願数・論文引用・新製品売上・R&D支出等の多様なイノベーション指標を国際的に比較分析した研究群。指標間の相関構造・国別測定の同等性・システム的偏向を明らかにし、複合指標（GII等）の妥当性を検証した。','国際イノベーション政策の比較可能性向上と指標設計の改善に貢献した。','measurement_policy_governance','D_directionality','イノベーション計量・比較研究','2005','macro','policy','measurement_comparison','["Castellacci, F.", "Archibugi, D.", "Cornell University"]','["Archibugi & Michie (1997) Technology globalisation", "Cornell/INSEAD/WIPO (2023) GII"]','イノベーション指標,国際比較,GII,複合指標','innovation indicators,international comparison,GII,composite index'),
('inno_pol_202','科学技術イノベーション政策評価のロジックモデル','Logic Model for Science Technology Innovation Policy Evaluation','政策インプット→活動→アウトプット→アウトカム→インパクトの因果連鎖を表すロジックモデルをSTI政策評価に適用した研究群。理論ベース評価（TBE）・貢献分析・因果推論の課題を整理し、政策立案者向けの実践的枠組みを提供した。','政府のR&D補助金・産学連携プログラム評価に科学的根拠を提供した。','measurement_policy_governance','D_directionality','政策評価理論','2008','macro','policy','logic_model_evaluation','["Rossi, P.H.", "Donaldson, S.I.", "Rogers, P.J."]','["Rossi et al. (2004) Evaluation: A systematic approach", "Rogers (2008) Using programme theory"]','ロジックモデル,政策評価,貢献分析,因果推論','logic model,policy evaluation,contribution analysis,causal inference'),
('inno_pol_203','イノベーション税制優遇政策の効果研究（R&D税控除）','R&D Tax Credit Policy Effectiveness Research','R&D費の税控除・Patent Box・イノベーション所得控除政策が民間R&D投資に与える効果を準実験・DID（差分の差分法）で推定した研究群。税制誘引の追加性（additionality）と受益企業の選択バイアス除去が主要方法論的課題となっている。','OECD各国のR&D税制設計と科学技術振興政策に実証的根拠を提供した。','measurement_policy_governance','D_directionality','税制・R&D政策評価','2000','macro','policy','additionality_estimation','["Hall, B.H.", "Van Reenen, J.", "Bloom, N."]','["Hall & Van Reenen (2000) R&D tax credits review", "Bloom et al. (2002) Do R&D tax credits work"]','R&D税控除,税制優遇,追加性,Patent Box','R&D tax credit,tax incentive,additionality,Patent Box'),
('inno_pol_204','国家イノベーションシステム比較研究（NIS比較）','National Innovation Systems Comparative Research','Lundvall・Nelson・Freemanらの国家イノベーションシステム（NIS）概念を比較制度分析の観点から実証検討した研究群。金融制度・教育制度・労働市場・産業構造のコンプリメンタリティがNISの多様性を形成することを示した。','国家競争力政策と産業政策設計に理論的根拠を提供した。','measurement_policy_governance','D_directionality','国家イノベーションシステム','1992','macro','system','systemic_innovation','["Lundvall, B.A.", "Nelson, R.R.", "Freeman, C."]','["Lundvall (1992) National Systems of Innovation", "Nelson (1993) National Innovation Systems"]','国家イノベーションシステム,NIS,比較制度分析,コンプリメンタリティ','national innovation system,NIS,comparative institutional analysis,complementarity'),
('inno_pol_205','特許法改革とイノベーション促進の実証研究','Empirical Research on Patent Law Reform and Innovation Promotion','特許期間・特許適格主題・強制実施権・特許プールなど特許制度改革がイノベーション・R&D・競争に与える効果を実証分析した研究群。Bayh-Dole法・TRIPS協定・米国特許改革法の影響が特に詳細に研究されている。','知的財産政策と競争政策のバランス設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','知的財産制度研究','1998','macro','policy','patent_reform_impact','["Jaffe, A.B.", "Lerner, J.", "Williams, H.L."]','["Jaffe & Lerner (2004) Innovation and Its Discontents", "Williams (2013) Intellectual property rights BRCA"]','特許法改革,Bayh-Dole,TRIPS,知的財産政策','patent law reform,Bayh-Dole,TRIPS,IP policy'),
('inno_pol_206','政府調達イノベーション政策研究（PPI）','Public Procurement for Innovation Policy Research','政府調達を通じたイノベーション促進（PPI：Public Procurement for Innovation）政策の設計・効果を分析した研究群。要件ベース調達・競争的対話・イノベーション・パートナーシップなどの調達手法が企業のイノベーション誘引に与える影響を検討した。','EUの公共調達指令改革と政府調達を活用した産業政策に実証的根拠を提供した。','measurement_policy_governance','D_directionality','公共調達政策研究','2007','macro','policy','demand_side_innovation','["Edler, J.", "Georghiou, L.", "Uyarra, E."]','["Edler & Georghiou (2007) Public procurement and innovation", "Uyarra & Flanagan (2010) Understanding public procurement"]','政府調達,PPI,需要側イノベーション政策,競争的対話','public procurement,PPI,demand-side innovation policy,competitive dialogue'),
('inno_pol_207','スマートスペシャリゼーション戦略の評価研究（EU）','Evaluation Research on Smart Specialization Strategy','EU地域政策の中核戦略「スマートスペシャリゼーション（RIS3）」の設計・実施・成果を評価した研究群。地域の比較優位特定・企業家的発見プロセス・RIS3の実施能力格差が主要テーマとなっている。','EU構造基金の産業政策活用と地域イノベーション政策の設計改善に貢献した。','measurement_policy_governance','D_directionality','地域イノベーション政策研究','2012','macro','policy','regional_specialization','["Foray, D.", "McCann, P.", "Ortega-Argilés, R."]','["Foray et al. (2012) Smart Specialisation", "McCann & Ortega-Argilés (2015) RIS3 implementation"]','スマートスペシャリゼーション,RIS3,地域産業政策,EU構造基金','smart specialization,RIS3,regional industrial policy,EU structural funds'),
('inno_pol_208','研究費配分メカニズムとイノベーション成果','Research Funding Allocation Mechanisms and Innovation Outcomes','競争的研究費（課題設定型・ボトムアップ型）と機関支援型研究費の配分比率がイノベーション成果・科学的生産性・リスクテイクに与える影響を分析した研究群。「ファンドアトラクション」と「マルチプロジェクト」の探索的研究への影響も検討されている。','研究資金配分政策と科学技術振興基本計画の設計改善に実証的根拠を提供した。','measurement_policy_governance','D_directionality','研究費配分政策研究','2003','macro','policy','research_funding_mechanism','["Jacob, M.", "Meek, V.L.", "Geuna, A."]','["Geuna (2001) Research funding allocation", "Jacob & Meek (2013) Scientific mobility"]','研究費配分,競争的研究費,機関支援,研究生産性','research funding,competitive grants,institutional support,research productivity'),
('inno_pol_209','規制サンドボックス政策の設計と評価','Regulatory Sandbox Policy Design and Evaluation','フィンテック・医療AI・自動運転向けの規制サンドボックス（試験的免除）政策の設計・運用・評価を分析した研究群。参加企業の選定基準・試験期間設計・学習成果の規制への反映・競争中立性が主要テーマとなっている。','新興技術の規制整備と産業政策の段階的設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','規制政策研究','2016','meso','policy','regulatory_experimentation','["Zetzsche, D.A.", "Buckley, R.P.", "Arner, D.W."]','["Zetzsche et al. (2017) Regulatory sandbox", "FCA (2015) UK regulatory sandbox"]','規制サンドボックス,フィンテック規制,試験的免除,規制イノベーション','regulatory sandbox,fintech regulation,regulatory experimentation,innovation regulation'),
('inno_pol_210','産学連携の政策効果研究（三重螺旋）','Policy Effect Research on University-Industry Collaboration: Triple Helix','大学・産業・政府の三者関係（Triple Helix）が地域イノベーションエコシステムに与える影響を分析した研究群。大学スピンオフ・共同研究・技術移転政策の成果と障壁を実証的に検討した。','産学連携政策・科学技術園設置・大学の第三の使命政策に実証的根拠を提供した。','measurement_policy_governance','D_directionality','三重螺旋・産学連携研究','2000','macro','policy','triple_helix_dynamics','["Etzkowitz, H.", "Leydesdorff, L.", "Gibbons, M."]','["Etzkowitz & Leydesdorff (2000) Triple Helix", "Gibbons et al. (1994) New production of knowledge"]','三重螺旋,産学連携,技術移転,大学スピンオフ','triple helix,university-industry collaboration,technology transfer,university spinoff'),
('inno_pol_211','イノベーション政策の失敗論とシステム失敗','Innovation Policy Failure Theory and Systemic Failure','市場の失敗（外部性・不確実性）だけでなく、「システムの失敗」（能力不足・ネットワーク失敗・制度の硬直性・認知失敗）をイノベーション政策介入の根拠として体系化した研究群。政府失敗との比較で政策介入の適切な範囲を論じた。','STI政策の理論的根拠の再構築と政策評価フレームの精緻化に貢献した。','measurement_policy_governance','D_directionality','イノベーション政策理論','2001','macro','policy','systemic_failure_theory','["Smith, K.", "Woolthuis, R.K.", "Hekkert, M.P."]','["Smith (2000) Innovation as a systemic phenomenon", "Woolthuis et al. (2005) System failure framework"]','システム失敗,政策介入根拠,市場失敗,イノベーション政策理論','system failure,policy rationale,market failure,innovation policy theory'),
('inno_pol_212','研究開発補助金の効果評価（傾向スコアマッチング）','R&D Subsidy Effect Evaluation Using Propensity Score Matching','政府R&D補助金の受給企業と非受給企業の革新性・生産性・雇用を比較した研究群。選択バイアスを傾向スコアマッチング・操作変数・RDDで除去する方法論が確立されており、補助金の追加性を厳密に推定した研究が蓄積されている。','R&D補助金政策の費用対効果分析と政策設計改善に実証的根拠を提供した。','measurement_policy_governance','D_directionality','R&D政策評価研究','2002','macro','policy','subsidy_additionality','["Czarnitzki, D.", "Caliendo, M.", "Klette, T.J."]','["Czarnitzki & Licht (2006) Additionality of public R&D grants", "Klette et al. (2000) Do subsidies to commercial R&D reduce market failures"]','R&D補助金,追加性,傾向スコアマッチング,政府助成','R&D subsidy,additionality,propensity score matching,government grant'),
('inno_pol_213','グリーンイノベーション政策研究（環境技術支援）','Green Innovation Policy Research: Environmental Technology Support','炭素税・排出量取引・環境技術補助金・グリーン調達等グリーンイノベーション政策がクリーン技術特許・投資・普及に与える影響を分析した研究群。Porterの仮説（規制が競争力を高める）の検証が重要テーマとなっている。','気候変動政策と産業競争力政策の統合設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','グリーンイノベーション政策研究','2005','macro','policy','environmental_policy_innovation','["Jaffe, A.B.", "Newell, R.G.", "Stavins, R.N."]','["Jaffe et al. (2005) Environmental policy and technological change", "Acemoglu et al. (2012) Directed technical change"]','グリーンイノベーション,環境政策,Porter仮説,炭素税','green innovation,environmental policy,Porter hypothesis,carbon tax'),
('inno_pol_214','イノベーション政策の政治経済学研究','Political Economy Research on Innovation Policy','イノベーション政策の内容がロビー活動・選挙圧力・政官財の関係・国際貿易交渉によってどのように形成されるかを分析した研究群。公共選択理論・Acemogluのインクルーシブvs搾取的制度論をSTI政策に適用した。','科学技術政策のガバナンス改革と民主的STI政策形成プロセスの設計に理論的根拠を提供した。','measurement_policy_governance','D_directionality','STI政策の政治経済学','2004','macro','policy','political_economy_innovation','["Acemoglu, D.", "Daron, A.", "Mazzucato, M."]','["Acemoglu & Robinson (2012) Why Nations Fail", "Mazzucato (2013) Entrepreneurial State"]','STI政策政治経済学,ロビー活動,公共選択,Mazzucato','STI policy political economy,lobbying,public choice,Mazzucato'),
('inno_pol_215','科学技術外交とイノベーション政策','Science Diplomacy and Innovation Policy','科学技術協力協定・技術同盟・ジョイントラボ等の国際科学技術外交が技術移転・共同研究・地政学的影響力に与える効果を分析した研究群。「科学の中立性」の前提と地政学的競争の緊張関係が重要テーマとなっている。','国際科学技術協力政策と技術安全保障戦略に実証的根拠を提供した。','measurement_policy_governance','D_directionality','科学外交研究','2010','macro','policy','science_diplomacy','["Rungius, C.", "Flink, T.", "Weingart, P."]','["Rungius & Flink (2020) Science diplomacy", "Weingart (1999) Science and politics"]','科学外交,技術同盟,国際研究協力,地政学','science diplomacy,technology alliance,international research cooperation,geopolitics'),
('inno_pol_216','イノベーション計測のフロンティア研究（無形資産）','Frontier Research on Innovation Measurement: Intangible Assets','ソフトウェア・ブランド・組織能力・データなど無形資産をR&D以外のイノベーション投資として国民勘定・企業会計に計上する方法論を開発した研究群。Corrado-Hulten-Sichel（CHS）フレームワークが代表的枠組みとなっている。','GDP統計の見直しと企業価値評価・産業政策設計に根本的影響を与えた。','measurement_policy_governance','D_directionality','無形資産計測研究','2005','macro','product','measurement_intangible','["Corrado, C.", "Hulten, C.", "Sichel, D."]','["Corrado et al. (2005) Measuring capital and technology", "Haskel & Westlake (2018) Capitalism without capital"]','無形資産,CHSフレームワーク,イノベーション投資計測,GDP統計','intangible assets,CHS framework,innovation investment measurement,GDP statistics'),
('inno_pol_217','官民連携（PPP）によるイノベーションプログラム評価','Evaluation of Public-Private Partnership Innovation Programs','EU Horizon・日本のSIP・米国ARPA-Eなど官民連携型の大型イノベーションプログラムの設計・実施・効果を分析した研究群。ミッション指向型R&D・産業選択・追加性・長期コミットメントが主要テーマとなっている。','大型官民連携政策プログラムの設計改善と成果評価方法論に貢献した。','measurement_policy_governance','D_directionality','官民連携イノベーション研究','2009','macro','policy','mission_innovation','["Mazzucato, M.", "Robinson, D.K.R.", "Weber, K.M."]','["Mazzucato (2018) Mission Economy", "Robinson & Weber (2020) Mission-oriented innovation"]','官民連携,ミッション指向,ARPA-E,SIP','PPP,mission-oriented,ARPA-E,SIP'),
('inno_pol_218','AIガバナンス政策の国際比較研究','International Comparative Research on AI Governance Policy','EU AI Act・中国AI規制・米国AI大統領令・OECDのAI原則等AIガバナンス政策の比較分析研究群。原則ベース vs 規則ベースアプローチ・リスク分類・執行メカニズムの国際差異を整理した。','グローバルAI規制の標準化議論と各国AI産業政策の設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','AIガバナンス政策研究','2019','macro','policy','ai_governance_comparison','["Calo, R.", "Dafoe, A.", "Roberts, H."]','["OECD (2019) AI principles", "EU Commission (2021) AI Act proposal"]','AIガバナンス,EU AI Act,AI規制,国際標準','AI governance,EU AI Act,AI regulation,international standards'),
('inno_pol_219','データガバナンスとイノベーション政策','Data Governance and Innovation Policy','GDPR・CCPA・データ国境移転規制・データ共有義務化等データガバナンス政策がデータ駆動型イノベーションに与える影響を分析した研究群。プライバシー保護とイノベーション促進の間のトレードオフ・データ信託・データスペース政策が主要テーマとなっている。','データ経済政策と個人情報保護制度の均衡設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','データガバナンス政策研究','2018','macro','policy','data_governance_innovation','["Rubinfeld, D.L.", "Gal, M.S.", "Cremer, J."]','["Cremer et al. (2019) Competition policy digital era", "Rubinfeld & Gal (2017) Big data restraints"]','データガバナンス,GDPR,データスペース,プライバシー-イノベーション','data governance,GDPR,data spaces,privacy-innovation tradeoff'),
('inno_pol_220','宇宙産業の規制とイノベーション政策','Space Industry Regulation and Innovation Policy','商業宇宙打ち上げ・衛星コンステレーション・月面資源採掘等の宇宙活動に関する規制フレームワークとイノベーション促進政策を分析した研究群。宇宙条約改訂・国家宇宙法・国際協調規制の設計課題が主要テーマとなっている。','商業宇宙産業政策と宇宙安全保障の法制度設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','宇宙政策研究','2015','macro','policy','space_regulation','["Lyall, F.", "Larsen, P.B.", "Jakhu, R.S."]','["Lyall & Larsen (2018) Space Law", "Jakhu & Pelton (2017) Commercial space"]','宇宙産業規制,商業宇宙法,宇宙条約,衛星規制','space industry regulation,commercial space law,Outer Space Treaty,satellite regulation'),
('inno_pol_221','技術安全保障と輸出規制政策研究','Technology Security and Export Control Policy Research','EAR・ITAR・EU輸出規制・日本の外為法等技術輸出規制がイノベーション・技術移転・研究開放性に与える影響を分析した研究群。研究安全保障・外国投資審査（CFIUS・FEFTA）との連携も重要テーマとなっている。','技術安全保障政策と科学技術の開放性・国際競争力の均衡設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','技術安全保障政策研究','2018','macro','policy','tech_security_policy','["Drezner, D.W.", "Hagerty, B.H.", "Reynolds, M.A."]','["Drezner (2019) Technology and US national security", "CSET (2021) Export controls technology"]','輸出規制,技術安全保障,CFIUS,外為法','export controls,technology security,CFIUS,FEFTA'),
('inno_pol_222','バイオテクノロジー規制とイノベーション政策','Biotechnology Regulation and Innovation Policy','遺伝子組換え・ゲノム編集・合成生物学・遺伝子ドライブ等バイオテクノロジーの規制フレームワークとイノベーション政策のトレードオフを分析した研究群。EU予防原則 vs 米国製品ベース規制の比較研究が特に蓄積されている。','バイオテクノロジー規制改革と医農薬産業の競争力政策に実証的根拠を提供した。','measurement_policy_governance','D_directionality','バイオテクノロジー政策研究','2003','macro','policy','biotech_regulation','["Jasanoff, S.", "Graff, G.D.", "Juma, C."]','["Jasanoff (2005) Designs on Nature", "Juma & Lee (2005) Innovation applying the lessons of nature"]','バイオテクノロジー規制,ゲノム編集,予防原則,合成生物学','biotechnology regulation,genome editing,precautionary principle,synthetic biology'),
('inno_pol_223','産業政策の復権：新産業政策研究','Return of Industrial Policy: New Industrial Policy Research','ワシントンコンセンサス後の「産業政策の復権」をめぐる理論・実証研究群。ミッション指向政策・垂直型vs水平型の論争・政府の失敗を最小化する設計原則・Daniら「デュアル政府失敗論」が代表的研究となっている。','半導体・EV・バイオ等の戦略産業政策（IRA・CHIPS Act等）の理論的根拠を提供した。','measurement_policy_governance','D_directionality','産業政策研究','2011','macro','policy','new_industrial_policy','["Rodrik, D.", "Dani, R.", "Lin, J.Y."]','["Rodrik (2004) Industrial policy 21st century", "Lin (2012) New structural economics"]','産業政策,新産業政策,ミッション指向,CHIPS Act','industrial policy,new industrial policy,mission-oriented,CHIPS Act'),
('inno_pol_224','スタートアップエコシステム政策評価','Startup Ecosystem Policy Evaluation','スタートアップビザ・ストックオプション税制・政府VC・イノベーター向け規制免除等スタートアップ支援政策の効果を分析した研究群。Startup Genome・Atomico等のエコシステム評価フレームの政策的活用も議論されている。','スタートアップエコシステム政策設計とアントレプレナーシップ促進に実証的根拠を提供した。','measurement_policy_governance','D_directionality','スタートアップ政策研究','2010','meso','policy','startup_ecosystem_policy','["Audretsch, D.B.", "Isenberg, D.J.", "Stam, E."]','["Audretsch & Thurik (2001) What is new about the new economy", "Isenberg (2010) Entrepreneurship ecosystem"]','スタートアップエコシステム,スタートアップ政策,ストックオプション,政府VC','startup ecosystem,startup policy,stock options,government VC'),
('inno_pol_225','プラットフォームエコノミーの競争政策研究','Competition Policy Research on Platform Economy','デジタルプラットフォームの独占的地位・セルフプレファレンス・ゼロプライス市場・データ独占に対する競争政策の適用と改革を分析した研究群。EU Digital Markets Act・米国反トラスト訴訟・日本特定デジタルプラットフォーム法の比較研究が含まれる。','デジタル経済の競争政策設計とプラットフォーム規制の国際標準化に実証的根拠を提供した。','measurement_policy_governance','D_directionality','デジタル競争政策研究','2018','macro','policy','digital_antitrust','["Tirole, J.", "Vestager, M.", "Scott Morton, F."]','["Tirole (2015) Digital economy competition", "Scott Morton et al. (2019) Committee for Study of Digital Platforms"]','デジタル競争政策,DMA,反トラスト,プラットフォーム規制','digital competition policy,DMA,antitrust,platform regulation'),
('inno_pol_226','気候イノベーション政策の国際比較（COP後）','International Comparison of Climate Innovation Policy Post-COP','パリ協定・各COP決定後の各国気候イノベーション政策（クリーンテック補助・炭素税・産業脱炭素ロードマップ）の比較分析研究群。政策手段の組み合わせ・政策一貫性・カーボンリーケージが主要テーマとなっている。','国際気候体制の実施政策設計と産業脱炭素ロードマップ評価に実証的根拠を提供した。','measurement_policy_governance','D_directionality','気候変動政策研究','2016','macro','policy','climate_innovation_policy','["Meckling, J.", "Kelsey, N.", "Biber, E."]','["Meckling et al. (2015) Winning coalition climate policy", "Grazi & van den Bergh (2008) Spatial welfare economics climate"]','気候イノベーション政策,炭素税,クリーンテック,COP','climate innovation policy,carbon tax,clean tech,COP'),
('inno_pol_227','健康技術評価（HTA）政策研究','Health Technology Assessment Policy Research','医薬品・医療機器・デジタルヘルスのHTA（健康技術評価）プロセスを分析した研究群。費用対効果閾値・QALYの倫理的問題・アダプティブHTA・患者視点の組み込み・国際HTA協調（EU HTA規制）が主要テーマとなっている。','医療イノベーションへの公的保険適用決定と医薬品価格政策に実証的根拠を提供した。','measurement_policy_governance','D_directionality','健康技術評価研究','2000','meso','policy','hta_policy','["Drummond, M.F.", "O''Brien, B.", "Claxton, K."]','["Drummond et al. (2015) Methods HTA", "Claxton et al. (2015) Methods for NICE"]','HTA,健康技術評価,QALY,費用対効果','HTA,health technology assessment,QALY,cost-effectiveness'),
('inno_pol_228','デジタル公共インフラ政策研究（DPI）','Digital Public Infrastructure Policy Research','アドハール・UPI・シンガポールSingPass等デジタル公共インフラの設計・ガバナンス・イノベーション促進効果を分析した研究群。政府主導デジタルID・デジタル決済・データ共有レイヤーの標準化が重要テーマとなっている。','発展途上国のデジタル経済政策と先進国の公的デジタルインフラ戦略に実証的根拠を提供した。','measurement_policy_governance','D_directionality','デジタル公共インフラ政策研究','2018','macro','policy','digital_public_infrastructure','["Iyer, L.", "Nathan, D.", "Kleven, H."]','["UNDP (2022) Digital Public Infrastructure", "World Bank (2023) DPI report"]','デジタル公共インフラ,DPI,アドハール,UPI','digital public infrastructure,DPI,Aadhaar,UPI'),
('inno_pol_229','ミッション指向型イノベーション政策の設計原則','Design Principles for Mission-Oriented Innovation Policy','アポロ計画・マンハッタン計画・気候ミッション等の先例からミッション指向型R&D政策の設計原則を抽出した研究群。問題の明確性・マルチアクター調整・多様な解決策の探索・適応的実施が核心原則として提案されている。','EU Horizon Europe ミッション設計とMazzucato流産業政策の実践に理論的根拠を提供した。','measurement_policy_governance','D_directionality','ミッション指向政策研究','2018','macro','policy','mission_oriented_design','["Mazzucato, M.", "Kattel, R.", "Larrue, P."]','["Mazzucato (2018) Mission-oriented research and innovation", "Larrue (2021) Mission-oriented innovation policy"]','ミッション指向,アポロ計画,気候ミッション,Mazzucato設計原則','mission-oriented,Apollo program,climate mission,Mazzucato design principles'),
('inno_pol_230','ファーサイト（政策フォーサイト）方法論研究','Policy Foresight Methodology Research','デルファイ法・シナリオ計画・技術ロードマップ・クリティカルテクノロジーアセスメント等の政策フォーサイト方法論を比較分析した研究群。参加型フォーサイト・オープンフォーサイト・クロスインパクト分析の進化が主要テーマとなっている。','STI政策の中長期計画と科学技術基本計画の策定プロセス改善に実証的根拠を提供した。','measurement_policy_governance','D_directionality','政策フォーサイト研究','1995','macro','policy','policy_foresight','["Miles, I.", "Blind, K.", "Popper, R."]','["Miles (2010) The development of technology foresight", "Blind (2012) Standardisation"]','政策フォーサイト,デルファイ,シナリオ計画,技術ロードマップ','policy foresight,Delphi,scenario planning,technology roadmapping'),
('inno_pol_231','研究倫理とイノベーション：デュアルユース研究規制','Research Ethics and Innovation: Dual-Use Research Regulation','生物テロ・サイバー兵器・自律型兵器システムに転用可能な「懸念のある二重用途研究（DURC）」の規制フレームワークを分析した研究群。研究の自由と安全保障の緊張関係・自主規制vs法的強制・国際協調の可能性が主要テーマとなっている。','バイオセーフティ政策・AI安全保障規制・研究倫理審査制度設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','研究倫理・安全保障研究','2005','macro','policy','dual_use_research','["Fink, S.L.", "Selgelid, M.J.", "Evans, N.G."]','["Fink (2013) Biosecurity dilemmas", "Selgelid (2009) Governance dual-use research"]','デュアルユース研究,DURC,研究倫理,バイオセーフティ','dual-use research,DURC,research ethics,biosafety'),
('inno_pol_232','ナノテクノロジー政策と社会倫理的課題','Nanotechnology Policy and Socio-Ethical Issues','ナノ材料のリスク規制・EHS（環境・健康・安全）測定・ELSI（倫理・法・社会的含意）・予防的アプローチの統合を分析した研究群。NEMS・カーボンナノチューブ・ナノ農薬の政策事例が特に研究されている。','ナノテクノロジー安全規制と責任あるイノベーション政策（RRI）の設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','ナノテクノロジー政策研究','2004','meso','policy','nanotechnology_policy','["Roco, M.C.", "Bainbridge, W.S.", "Bowman, D.M."]','["Roco & Bainbridge (2001) Societal implications of nanoscience", "Bowman & Hodge (2007) Governing nanotechnology"]','ナノテクノロジー政策,EHS,ELSI,予防的アプローチ','nanotechnology policy,EHS,ELSI,precautionary approach'),
('inno_pol_233','イノベーション人材政策（STEM・STEAM）','Innovation Human Capital Policy: STEM and STEAM','STEM教育投資・高度人材ビザ・研究者流動性政策がイノベーション成果に与える効果を分析した研究群。移民イノベーター・女性STEM・STEM不足論への批判的検討が含まれる。H-1Bビザ・EU Blue Card・ポイント制移民政策の比較研究も含まれる。','科学技術人材政策と高度人材誘致戦略に実証的根拠を提供した。','measurement_policy_governance','D_directionality','人材イノベーション政策研究','2006','macro','policy','stem_human_capital','["Kerr, W.R.", "Hunt, J.", "Stephan, P.E."]','["Kerr & Lincoln (2010) H-1B visa", "Hunt (2011) Immigrants in US science"]','STEM政策,高度人材ビザ,研究者流動性,移民イノベーター','STEM policy,high-skill visa,researcher mobility,immigrant innovator'),
('inno_pol_234','科学技術指標のジェンダー分析','Gender Analysis of Science and Technology Indicators','STEM参入・特許発明者・研究費取得・学術誌編集委員のジェンダーギャップを計測・分析した研究群。UNESCO・OECDの国際比較データを用いた実証研究が主流となっており、ガラスの天井・暗黙のバイアス・採用委員会構成の影響が解明されている。','科学技術政策のジェンダー主流化と大学・研究機関のDEI推進に実証的根拠を提供した。','measurement_policy_governance','D_directionality','ジェンダーSTI政策研究','2008','macro','policy','gender_innovation_gap','["Larivière, V.", "Ni, C.", "Gingras, Y."]','["Larivière et al. (2013) Bibliometrics gender gap", "UNESCO (2021) Women in science"]','ジェンダー,STEM格差,女性研究者,科学技術政策','gender,STEM gap,women in STEM,science technology policy'),
('inno_pol_235','イノベーション地理学と集積効果研究','Innovation Geography and Agglomeration Effects Research','シリコンバレー・ボストン・深センなどイノベーションクラスターの成功要因と集積経済効果を分析した研究群。知識スピルオーバー・人材流動性・VC地理・大学近接性が集積を規定する構造を解明した。','クラスター政策・科学技術特区・産業立地政策の設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','イノベーション地理・クラスター研究','1998','macro','system','agglomeration_innovation','["Porter, M.E.", "Saxenian, A.", "Glaeser, E.L."]','["Porter (1998) Clusters and new economics of competition", "Saxenian (1994) Regional Advantage"]','イノベーションクラスター,集積効果,シリコンバレー,知識スピルオーバー','innovation cluster,agglomeration effects,Silicon Valley,knowledge spillover'),
('inno_pol_236','テクノロジーアセスメントの制度化研究','Institutionalization of Technology Assessment Research','議会技術評価局（OTA・STOA・TAB等）の設立・機能・廃止・復活を比較分析した研究群。政策立案者への科学技術助言機能・参加型TA・コンストラクティブTA・リアルタイムTAの進化が主要テーマとなっている。','科学技術政策助言の制度設計と民主的STIガバナンスに実証的根拠を提供した。','measurement_policy_governance','D_directionality','テクノロジーアセスメント研究','2000','macro','policy','technology_assessment_institution','["Vig, N.J.", "Paschen, H.", "Schaper-Rinkel, P."]','["Vig & Paschen (2000) Parliaments and technology", "Schaper-Rinkel (2015) OTA reinvention"]','テクノロジーアセスメント,OTA,議会TA,参加型TA','technology assessment,OTA,parliamentary TA,participatory TA'),
('inno_pol_237','レスポンシブル・リサーチ・イノベーション（RRI）政策研究','Responsible Research and Innovation Policy Research','EU Horizonが採用したRRI（責任ある研究とイノベーション）フレームワーク——公正・予見・反省性・応答性・包摂性の五次元——の政策実践を評価した研究群。RRIの主流化の難しさと実施ギャップが繰り返し確認されている。','AI・バイオテク・ナノテクの倫理ガバナンス設計とEU研究プログラム評価基準に実証的根拠を提供した。','measurement_policy_governance','D_directionality','RRI政策研究','2013','macro','policy','rri_governance','["Owen, R.", "Stilgoe, J.", "Macnaghten, P."]','["Owen et al. (2013) Responsible research and innovation", "Stilgoe et al. (2013) Developing a framework for RRI"]','RRI,責任あるイノベーション,倫理ガバナンス,EU Horizon','RRI,responsible innovation,ethics governance,EU Horizon'),
('inno_pol_238','インパクト投資と社会的イノベーション政策','Impact Investing and Social Innovation Policy','社会的課題解決を目的とするインパクト投資・SIB（社会的影響力債券）・ブレンデッドファイナンスの政策設計・効果測定を分析した研究群。IMP（インパクト管理プロジェクト）・SROI（社会的投資収益率）の方法論的問題と標準化が主要テーマとなっている。','社会的インパクト政策と社会課題解決投資の評価インフラ設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','社会的インパクト政策研究','2012','macro','policy','impact_investing_policy','["Bugg-Levine, A.", "Emerson, J.", "O''Donohoe, N."]','["Bugg-Levine & Emerson (2011) Impact investing", "O''Donohoe et al. (2010) Impact investments"]','インパクト投資,SIB,SROI,ブレンデッドファイナンス','impact investing,SIB,SROI,blended finance'),
('inno_pol_239','技術中立性原則とイノベーション政策','Technology Neutrality Principle and Innovation Policy','規制・調達・補助金における技術中立性原則（特定技術を優遇しない）とミッション指向政策（特定技術を支援する）の緊張関係を分析した研究群。再生可能エネルギー・デジタル技術・EV政策を事例として技術選択の政策的含意を検討した。','グリーン産業政策と競争政策の整合的設計に理論的根拠を提供した。','measurement_policy_governance','D_directionality','技術政策設計研究','2008','macro','policy','technology_neutrality','["Hancher, L.", "Larouche, P.", "Sauter, W."]','["Hancher & Sauter (2012) EU competition and state aid law", "Larouche (2009) Technology neutrality"]','技術中立性,ミッション指向,EV政策,競争政策','technology neutrality,mission-oriented,EV policy,competition policy'),
('inno_pol_240','知識移転効率性の計測研究','Knowledge Transfer Efficiency Measurement Research','大学・公的研究機関から産業への知識移転（特許ライセンス・スピンオフ・共同研究・非公式移転）の多様なチャネルの相対的効率性を計測・比較した研究群。コーエン・ネルソン・ウォルシュ調査等の大規模サーベイデータが活用されている。','大学技術移転政策とTLOの設計改善に実証的根拠を提供した。','measurement_policy_governance','D_directionality','知識移転計測研究','2002','macro','policy','knowledge_transfer_measurement','["Cohen, W.M.", "Nelson, R.R.", "Walsh, J.P."]','["Cohen et al. (2002) Links and impacts university research", "Fontana et al. (2006) Firm-university knowledge transfer"]','知識移転,大学TLO,ライセンス,スピンオフ計測','knowledge transfer,university TLO,licensing,spinoff measurement'),
('inno_pol_241','イノベーション政策評価のランダム化比較試験（RCT）','Randomized Controlled Trials in Innovation Policy Evaluation','中小企業支援・スタートアップ補助金・メンタリングプログラム等のイノベーション政策をRCTで評価した研究群。ビジネスサービス支援・輸出支援・融資保証の因果効果を厳密に推定した事例が蓄積されている。','イノベーション政策のエビデンスベース化と政策学習の科学的基盤構築に貢献した。','measurement_policy_governance','D_directionality','STI政策評価方法論','2012','macro','policy','rct_policy_evaluation','["Lerner, J.", "McKenzie, D.", "Bruhn, M."]','["Lerner (2009) Boulevard of Broken Dreams", "McKenzie (2017) Identifying and spurring high-growth entrepreneurship"]','イノベーション政策RCT,因果推論,政策評価,中小企業支援','innovation policy RCT,causal inference,policy evaluation,SME support'),
('inno_pol_242','研究機関ガバナンスと科学生産性','Research Institution Governance and Scientific Productivity','大学・国立研究所・民間研究所の組織ガバナンス（自律性・説明責任・評価制度）が科学的生産性・イノベーション成果に与える影響を分析した研究群。「評価疲れ」・研究評価の多様性・学際研究への阻害等が研究されている。','研究機関改革と研究評価制度の設計改善に実証的根拠を提供した。','measurement_policy_governance','D_directionality','研究機関ガバナンス研究','2005','macro','policy','research_governance','["Paradeise, C.", "Reale, E.", "Godin, B."]','["Paradeise et al. (2009) University governance and research", "Godin (2009) Research performance indicators"]','研究機関ガバナンス,研究評価,大学自律性,評価疲れ','research governance,research evaluation,university autonomy,evaluation fatigue'),
('inno_pol_243','イノベーション統計の標準化（Frascati・Oslo マニュアル）','Standardization of Innovation Statistics: Frascati and Oslo Manuals','OECD Frascatiマニュアル（R&D統計）とOsloマニュアル（イノベーション統計）の改訂過程・概念的問題・国際比較可能性を分析した方法論的研究群。Osloマニュアル第4版（2018）でのビジネスイノベーション概念の拡張が特に検討されている。','国際イノベーション比較統計の改善と政策立案のためのエビデンス基盤強化に貢献した。','measurement_policy_governance','D_directionality','イノベーション統計標準化研究','1992','macro','policy','innovation_statistics_standard','["OECD", "Eurostat", "Smith, K."]','["OECD (2015) Frascati Manual 2015", "OECD/Eurostat (2018) Oslo Manual 4th edition"]','Frascatiマニュアル,Osloマニュアル,R&D統計,イノベーション統計','Frascati Manual,Oslo Manual,R&D statistics,innovation statistics'),
('inno_pol_244','テクノロジーガバナンスの共同規制研究','Co-Regulation Research on Technology Governance','自主規制・共同規制・規制的共同統治（co-governance）など政府・産業・市民の協働による新興技術ガバナンスを分析した研究群。DNAデータベース・インターネットコンテンツ・ソーシャルメディアの共同規制事例が特に蓄積されている。','AI・バイオテク・プラットフォームの次世代規制設計に理論的根拠を提供した。','measurement_policy_governance','D_directionality','共同規制・ガバナンス研究','2003','macro','policy','co_regulation_governance','["Black, J.", "Gunningham, N.", "Grabosky, P."]','["Black (2001) Decentring regulation", "Gunningham & Grabosky (1998) Smart regulation"]','共同規制,自主規制,テクノロジーガバナンス,新興技術規制','co-regulation,self-regulation,technology governance,emerging technology regulation'),
('inno_pol_245','医薬品価格規制とイノベーションインセンティブ','Drug Price Regulation and Innovation Incentives','価格規制（参照薬価・強制実施権・交渉価格上限）が製薬R&D投資・新薬承認数・治療革新に与える影響を分析した研究群。TRIPS柔軟性・IRAインフレ削減法の医薬品価格条項の影響研究も含まれる。','医薬品価格政策設計とアクセス-イノベーションのトレードオフ管理に実証的根拠を提供した。','measurement_policy_governance','D_directionality','医薬品価格政策研究','2004','macro','policy','drug_price_innovation','["Danzon, P.M.", "Towse, A.", "Lakdawalla, D.N."]','["Danzon & Towse (2003) Differential pricing", "Lakdawalla (2018) Economics of drug pricing"]','医薬品価格規制,製薬R&D,TRIPS,IRA','drug price regulation,pharmaceutical R&D,TRIPS,IRA'),
('inno_pol_246','ネットワーク中立性政策とイノベーション','Net Neutrality Policy and Innovation','インターネットのネットワーク中立性（NNP）規制の廃止・維持がエッジイノベーション・スタートアップ・コンテンツ多様性に与える影響を分析した研究群。FCC Open Internet Rule・EU Open Internet Regulation・廃止後の実証研究が含まれる。','通信規制政策とデジタルイノベーション政策の整合性設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','通信・デジタル政策研究','2015','macro','policy','net_neutrality_innovation','["Wu, T.", "Economides, N.", "Bauer, J.M."]','["Wu (2003) Network neutrality broadband", "Economides & Hermalin (2012) Net neutrality economics"]','ネットワーク中立性,NNP,エッジイノベーション,FCC','net neutrality,NNP,edge innovation,FCC'),
('inno_pol_247','深海・極地探査技術政策研究','Deep Sea and Polar Exploration Technology Policy Research','深海底鉱物資源探査・南極科学ステーション・北極航路における技術開発とガバナンスを分析した研究群。UNCLOS・南極条約・国際海底機構（ISA）の規制フレームと技術革新の相互作用が主要テーマとなっている。','深海資源政策と極地科学外交に実証的根拠を提供した。','measurement_policy_governance','D_directionality','海洋・極地政策研究','2010','macro','policy','ocean_polar_policy','["Mero, J.L.", "Glasby, G.P.", "Ardron, J.A."]','["Glasby (2006) Deep seabed minerals", "Ardron et al. (2014) Deep sea governance"]','深海探査,海底鉱物,南極条約,UNCLOS','deep sea exploration,seabed minerals,Antarctic Treaty,UNCLOS'),
('inno_pol_248','中小企業イノベーション政策のヨーロッパ比較研究','European Comparative Research on SME Innovation Policy','EUのSMEイノベーション支援（EIC・EUREKA・ESIF）と加盟国の中小企業政策の整合性・補完性・効果を比較分析した研究群。EU研究枠組みプログラムへのSME参加障壁・マッチングファンドの効果が主要テーマとなっている。','EU中小企業政策とイノベーション支援プログラム設計の改善に実証的根拠を提供した。','measurement_policy_governance','D_directionality','EU中小企業政策研究','2008','macro','policy','eu_sme_innovation','["Audretsch, D.B.", "Bögenhold, D.", "Qian, H."]','["Audretsch et al. (2014) SME policy EU", "OECD (2021) SME outlook"]','EU中小企業政策,EIC,EUREKA,SMEイノベーション','EU SME policy,EIC,EUREKA,SME innovation'),
('inno_pol_249','ナショナルラボとイノベーションシステム','National Laboratories and Innovation Systems','DOE国立研究所（LANL・ORNL等）・NIMS・産総研・CEA等の国立研究機関がイノベーションシステムに果たす役割を分析した研究群。基礎研究・応用橋渡し・スピンオフ・人材供給の四機能の有効性と組織設計が主要テーマとなっている。','国立研究機関の役割再設計と公的R&D投資戦略に実証的根拠を提供した。','measurement_policy_governance','D_directionality','国立研究機関政策研究','2004','macro','policy','national_lab_innovation','["Branscomb, L.M.", "Fong, G.R.", "Auerswald, P.E."]','["Branscomb & Keller (1998) Investing in innovation", "Fong (2001) Technology leapfrogging"]','国立研究機関,DOE国立研究所,産総研,橋渡し研究','national laboratory,DOE lab,AIST,translational research'),
('inno_pol_250','教育とイノベーション：高等教育政策研究','Education and Innovation: Higher Education Policy Research','大学教育水準・学術研究費・大学ランキングシステムがイノベーション成果・起業家輩出・産業競争力に与える影響を分析した研究群。世界大学ランキングの影響・大学のモード2知識生産・博士課程改革が主要テーマとなっている。','高等教育政策改革とイノベーション人材育成政策の設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','高等教育イノベーション政策研究','2003','macro','policy','higher_education_innovation','["Marginson, S.", "Cantwell, B.", "Salmi, J."]','["Marginson (2016) World university rankings", "Salmi (2009) Challenge of establishing world-class universities"]','高等教育政策,大学ランキング,博士課程,研究大学','higher education policy,university ranking,PhD program,research university');
